
(function(){
  const MFR_PRINT_LOGO = 'data:image/png;base64,';
  const COMPANY = {
    name:'My Family Roofer', tagline:'Protecting Your Home Like Family', contact:'Brian Barnes',
    email:'brian@myfamilyroofer.com', phone:'(970) 292-6927', address:'2515 Baxter Place, Fort Collins, CO 80526'
  };
  function esc(v){ return String(v ?? '').replace(/[&<>"']/g, m => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m])); }
  function money(v){ v = Number(v || 0); return v.toLocaleString(undefined,{style:'currency',currency:'USD'}); }
  function dt(v){ if(!v) return '—'; const d = new Date(v); return isNaN(d) ? String(v) : d.toLocaleDateString(); }
  function nameOf(c, fallback){ if(!c) return fallback || 'Customer'; return c.name || c.customer_name || [c.first_name,c.last_name].filter(Boolean).join(' ') || fallback || 'Customer'; }
  function addr(c,j){
    const parts=[];
    const street = j?.address || j?.project_address || j?.street || c?.street || c?.address || '';
    const city = j?.city || c?.city || ''; const state = j?.state || c?.state || ''; const zip = j?.zip || j?.zipcode || c?.zip || c?.zipcode || '';
    if(street) parts.push(street); const line2=[city,state,zip].filter(Boolean).join(', ').replace(', ,', ','); if(line2) parts.push(line2);
    return parts.length ? parts.join('<br>') : '—';
  }
  async function one(table, id){ if(!id || !window._sb) return null; try{ const r=await _sb.from(table).select('*').eq('id',id).single(); return r.error ? null : r.data; }catch(e){ return null; } }
  async function loadEstimate(id){
    let e=null; try{ const r=await _sb.from('v_estimates_full').select('*').eq('id',id).single(); if(!r.error) e=r.data; }catch(err){}
    if(!e){ const r=await _sb.from('estimates').select('*').eq('id',id).single(); if(r.error) throw r.error; e=r.data; }
    let lines=[]; try{ const lr=await _sb.from('estimate_line_items').select('*').eq('estimate_id',id).order('display_order',{ascending:true}); if(!lr.error) lines=lr.data||[]; }catch(err){}
    const j = await one('jobs', e.job_id);
    const c = await one('customers', e.customer_id || j?.customer_id);
    return {estimate:e, lines, job:j, customer:c};
  }
  async function loadInvoice(id){
    let i=null; try{ const r=await _sb.from('v_invoices_full').select('*').eq('id',id).single(); if(!r.error) i=r.data; }catch(err){}
    if(!i){ const r=await _sb.from('invoices').select('*').eq('id',id).single(); if(r.error) throw r.error; i=r.data; }
    let lines=[]; try{ const lr=await _sb.from('estimate_line_items').select('*').eq('invoice_id',id).order('display_order',{ascending:true}); if(!lr.error) lines=lr.data||[]; }catch(err){}
    if(!lines.length && i.estimate_id){ try{ const lr=await _sb.from('estimate_line_items').select('*').eq('estimate_id',i.estimate_id).order('display_order',{ascending:true}); if(!lr.error) lines=lr.data||[]; }catch(err){} }
    const j = await one('jobs', i.job_id);
    const c = await one('customers', i.customer_id || j?.customer_id);
    let pays=[]; try{ const pr=await _sb.from('invoice_payments').select('*').eq('invoice_id',id); if(!pr.error) pays=pr.data||[]; }catch(err){}
    return {invoice:i, lines, job:j, customer:c, payments:pays};
  }
  function lineRows(lines){
    if(!lines || !lines.length) return '<tr><td><div class="mfr-clean-line-title">Roofing project</div><span class="mfr-clean-line-type">job</span></td><td class="num">1 job</td><td class="num">—</td><td class="num"><strong>—</strong></td></tr>';
    return lines.map(l=>`<tr><td><div class="mfr-clean-line-title">${esc(l.item_name || l.name || 'Line item')}</div><span class="mfr-clean-line-type">${esc((l.item_type||'item').replace(/_/g,' '))}</span></td><td class="num">${esc(l.quantity || '')} ${esc(l.unit_label || l.unit || '')}</td><td class="num">${money(l.unit_price)}</td><td class="num"><strong>${money(l.total_price ?? (Number(l.quantity||0)*Number(l.unit_price||0)))}</strong></td></tr>`).join('');
  }
  function header(kind, number, amountLabel, amount){
    return `<div class="mfr-clean-head"><div class="mfr-clean-brand"><img src="${MFR_PRINT_LOGO}" alt="My Family Roofer"><div><h3>${COMPANY.name}</h3><p>${COMPANY.tagline}<br>${COMPANY.contact} · ${COMPANY.phone} · ${COMPANY.email}</p></div></div><div class="mfr-clean-title"><small>${esc(kind)}</small><strong>${esc(number || '')}</strong><p style="margin:6px 0 0;color:#dbeafe;font-weight:800">${esc(amountLabel)} ${money(amount)}</p></div></div>`;
  }
  function estimateDoc(b){
    const e=b.estimate, c=b.customer, j=b.job, total=Number(e.total_amount || e.total || 0), deposit=total*.5, cname=nameOf(c,e.customer_name);
    return `<div class="mfr-clean-doc">${header('Roof Replacement Quote', e.estimate_number || 'Estimate', 'Total', total)}<div class="mfr-clean-body"><div class="mfr-clean-grid"><div class="mfr-clean-card"><label>Customer</label><strong>${esc(cname)}</strong><p>${addr(c,j)}${c?.email?'<br>'+esc(c.email):''}${c?.phone?'<br>'+esc(c.phone):''}</p></div><div class="mfr-clean-card"><label>Project</label><strong>${esc(j?.job_type || 'Roof Replacement')}</strong><p>${addr(c,j)}<br>Status: ${esc(j?.status || e.status || 'draft')}</p></div><div class="mfr-clean-card"><label>My Family Roofer</label><strong>${COMPANY.contact}</strong><p>${COMPANY.phone}<br>${COMPANY.email}<br>${COMPANY.address}</p></div></div><div class="mfr-clean-meta"><div><span>Estimate #</span><b>${esc(e.estimate_number || '')}</b></div><div><span>Status</span><b>${esc(e.status || 'draft')}</b></div><div><span>Date</span><b>${dt(e.estimate_date || e.created_at)}</b></div><div><span>Valid Until</span><b>${dt(e.valid_until)}</b></div></div><table class="mfr-clean-table"><thead><tr><th>Selected Options & Upgrades</th><th class="num">Qty</th><th class="num">Rate</th><th class="num">Total</th></tr></thead><tbody>${lineRows(b.lines)}</tbody></table><div class="mfr-clean-totals"><div class="row"><span>Subtotal</span><strong>${money(e.subtotal || total)}</strong></div><div class="row"><span>Suggested 50% Deposit</span><strong>${money(deposit)}</strong></div><div class="row grand"><span>Total</span><strong>${money(total)}</strong></div></div><div class="mfr-clean-notes"><div class="mfr-clean-note"><h4>Agreement Summary</h4><p>This quote allows My Family Roofer to lock in pricing, reserve scheduling and materials, and assist with insurance/supplementing where applicable. No obligation until material ordering is authorized and materials are delivered.</p></div><div class="mfr-clean-note"><h4>Payment & Insurance</h4><p>Insurance work is based on the final approved scope and pricing, plus any selected upgrades or add-ons. Decking or uncovered conditions may be handled separately.</p></div></div></div></div>`;
  }
  function invoiceDoc(b){
    const i=b.invoice, c=b.customer, j=b.job, total=Number(i.total_amount || i.subtotal || 0), paid=Number(i.amount_paid || 0) || (b.payments||[]).reduce((s,p)=>s+Number(p.amount||0),0), bal=Number(i.balance_due ?? (total-paid)), cname=nameOf(c,i.customer_name);
    return `<div class="mfr-clean-doc">${header('Invoice', i.invoice_number || 'Invoice', 'Balance Due', bal)}<div class="mfr-clean-body"><div class="mfr-clean-grid"><div class="mfr-clean-card"><label>From</label><strong>${COMPANY.name}</strong><p>${COMPANY.contact}<br>${COMPANY.address}<br>${COMPANY.email}<br>${COMPANY.phone}</p></div><div class="mfr-clean-card"><label>Bill To</label><strong>${esc(cname)}</strong><p>${addr(c,j)}${c?.email?'<br>'+esc(c.email):''}${c?.phone?'<br>'+esc(c.phone):''}</p></div><div class="mfr-clean-card"><label>Project</label><strong>${esc(j?.job_type || 'Roof Replacement')}</strong><p>${addr(c,j)}<br>Status: ${esc(j?.status || i.status || 'sent')}</p></div></div><div class="mfr-clean-meta"><div><span>Invoice Date</span><b>${dt(i.invoice_date || i.created_at)}</b></div><div><span>Due Date</span><b>${dt(i.due_date)}</b></div><div><span>Status</span><b>${esc(String(i.status || 'sent').toUpperCase())}</b></div><div><span>Balance Due</span><b>${money(bal)}</b></div></div><table class="mfr-clean-table"><thead><tr><th>Description</th><th class="num">Qty</th><th class="num">Rate</th><th class="num">Amount</th></tr></thead><tbody>${lineRows(b.lines)}</tbody></table><div class="mfr-clean-totals"><div class="row"><span>Subtotal</span><strong>${money(i.subtotal || total)}</strong></div><div class="row"><span>Payments Applied</span><strong>${money(paid)}</strong></div><div class="row"><span>Suggested 50% Deposit</span><strong>${money(total*.5)}</strong></div><div class="row grand"><span>Balance Due</span><strong>${money(bal)}</strong></div></div><div class="mfr-clean-notes"><div class="mfr-clean-note"><h4>Payment & Insurance Work</h4><p>Payment is based on the final price mutually agreed upon with the insurance company for the approved scope of work, plus any selected add-ons or upgrades.</p></div><div class="mfr-clean-note"><h4>Late Payment Policy</h4><p>Unpaid balances remaining 30 days or more from the invoice date may be subject to a 3% late fee every 30 days until paid in full.</p></div></div></div></div>`;
  }
  function printCss(){ return `*{box-sizing:border-box} html,body{margin:0;padding:0;background:#fff;color:#0f172a;font-family:Arial,Helvetica,sans-serif;-webkit-print-color-adjust:exact;print-color-adjust:exact} @page{size:letter;margin:.45in} body{font-size:11px}.mfr-print-wrap{max-width:7.6in;margin:0 auto}.mfr-clean-doc{border:1px solid #dbe7f5;border-radius:0;overflow:hidden;box-shadow:none}.mfr-clean-head{display:flex;align-items:center;justify-content:space-between;gap:16px;background:linear-gradient(135deg,#06163d,#0b5ed7 60%,#1597e8);color:#fff;padding:16px 18px}.mfr-clean-brand{display:flex;align-items:center;gap:12px}.mfr-clean-brand img{display:block;width:112px!important;max-width:112px!important;height:auto!important;max-height:72px!important;object-fit:contain;background:#fff;border-radius:8px;padding:5px}.mfr-clean-brand h3{font-size:21px;margin:0 0 2px;font-weight:900}.mfr-clean-brand p{margin:0;font-size:10px;line-height:1.35;color:#eaf4ff}.mfr-clean-title{text-align:right;color:#fff}.mfr-clean-title small{display:block;text-transform:uppercase;letter-spacing:.16em;font-size:9px;color:#dbeafe;font-weight:900}.mfr-clean-title strong{font-size:18px;display:block;margin-top:2px}.mfr-clean-title p{font-size:11px}.mfr-clean-body{padding:16px 18px}.mfr-clean-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:9px;margin-bottom:12px}.mfr-clean-card{background:#f8fafc;border:1px solid #e2e8f0;border-radius:8px;padding:9px;min-height:82px}.mfr-clean-card label{display:block;color:#64748b;font-size:8.5px;letter-spacing:.12em;text-transform:uppercase;font-weight:900;margin-bottom:5px}.mfr-clean-card strong{display:block;font-size:11.5px;margin-bottom:3px}.mfr-clean-card p{margin:0;font-size:9.4px;line-height:1.32;color:#334155}.mfr-clean-meta{display:grid;grid-template-columns:repeat(4,1fr);gap:7px;margin-bottom:12px}.mfr-clean-meta div{background:#eff6ff;border:1px solid #bfdbfe;border-radius:8px;padding:8px}.mfr-clean-meta span{display:block;color:#64748b;font-size:8px;letter-spacing:.10em;text-transform:uppercase;font-weight:900;margin-bottom:2px}.mfr-clean-meta b{font-size:11.5px;white-space:nowrap}.mfr-clean-table{width:100%;border-collapse:collapse;border:1px solid #e2e8f0;margin-bottom:10px}.mfr-clean-table th{background:#f1f5f9;color:#475569;font-size:8px;letter-spacing:.08em;text-transform:uppercase;text-align:left;padding:7px}.mfr-clean-table td{padding:6px 7px;border-top:1px solid #edf2f7;vertical-align:top}.mfr-clean-table .num{text-align:right;white-space:nowrap}.mfr-clean-line-title{font-size:10px;font-weight:800}.mfr-clean-line-type{display:block;font-size:8.6px;color:#64748b;margin-top:1px;text-transform:capitalize}.mfr-clean-totals{margin-left:auto;width:265px;border:1px solid #bfdbfe;background:#f8fbff;margin-bottom:10px}.mfr-clean-totals .row{display:flex;justify-content:space-between;padding:6px 9px;border-bottom:1px solid #dbeafe;font-size:9.6px}.mfr-clean-totals .row:last-child{border-bottom:0}.mfr-clean-totals .grand{background:#071947;color:#fff;font-weight:900;font-size:12px}.mfr-clean-notes{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-top:9px;break-inside:avoid}.mfr-clean-note{background:#f8fafc;border-left:4px solid #2563eb;border-radius:7px;padding:8px;color:#475569;break-inside:avoid}.mfr-clean-note h4{font-size:9.5px;margin:0 0 4px;color:#0f172a;letter-spacing:.08em;text-transform:uppercase}.mfr-clean-note p{margin:0;font-size:8.8px;line-height:1.32}.mfr-clean-actions{display:none!important}@media print{a[href]:after{content:""!important}}`; }
  function openPrint(title, doc){
    const html = `<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>${esc(title)}</title><style>${printCss()}</style></head><body><div class="mfr-print-wrap">${doc}</div><script>window.onload=function(){setTimeout(function(){window.focus();window.print();},350)};<\/script>
</body></html>`;
    const w = window.open('', '_blank'); if(!w){ toast && toast('Popup blocked. Allow popups to print/save PDF.', 'error'); return; }
    w.document.open(); w.document.write(html); w.document.close();
  }
  window.mfrPrintBrandedEstimate = async function(id){ try{ const b=await loadEstimate(id); openPrint('Estimate '+(b.estimate.estimate_number||''), estimateDoc(b)); }catch(e){ console.error(e); toast('Could not print estimate: '+(e.message||e),'error'); } };
  window.mfrPrintBrandedInvoice = async function(id){ try{ const b=await loadInvoice(id); openPrint('Invoice '+(b.invoice.invoice_number||''), invoiceDoc(b)); }catch(e){ console.error(e); toast('Could not print invoice: '+(e.message||e),'error'); } };
  window.viewEstimateModal = async function(id){
    try{ const b=await loadEstimate(id); const e=b.estimate; const actions=`<div class="mfr-clean-actions"><button class="btn btn-primary" onclick="mfrShowQuoteLinks && mfrShowQuoteLinks('${esc(e.job_id||'')}','${esc(e.quote_code||'')}')">Quote Link</button><button class="btn btn-success" onclick="convertEstimateToInvoice('${esc(e.id)}')">Convert to Invoice</button><button class="btn btn-outline" onclick="mfrPrintBrandedEstimate('${esc(e.id)}')">Print / Save PDF</button></div>`; mfrModal('Estimate '+esc(e.estimate_number||''), actions + estimateDoc(b), '1080px'); }catch(err){ console.error(err); toast('Could not load estimate: '+(err.message||err),'error'); }
  };
  window.viewInvoiceModal = async function(id){
    try{ const b=await loadInvoice(id); const i=b.invoice; const paid=String(i.status||'').toLowerCase()==='paid'; const actions=`<div class="mfr-clean-actions"><button class="btn btn-success" ${paid?'disabled':''} onclick="markInvoicePaid('${esc(i.id)}')">Mark Paid</button><button class="btn btn-primary" onclick="mfrPrintBrandedInvoice('${esc(i.id)}')">Print / Save PDF</button><button class="btn btn-danger" onclick="deleteInvoiceConfirm && deleteInvoiceConfirm('${esc(i.id)}')">Delete</button></div>`; mfrModal('Invoice '+esc(i.invoice_number||''), actions + invoiceDoc(b), '1080px'); }catch(err){ console.error(err); toast('Could not load invoice: '+(err.message||err),'error'); }
  };
})();
